/**
 * Notification validators — pure validation functions for notification preferences.
 *
 * Extracted from PreferencesService.shouldSendNotification(). These functions
 * check user preferences without any side effects or data store access.
 */

import type { NotificationType } from '../models/notification.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';

/**
 * Result of a notification preference check.
 * When `allowed` is false, `reason` explains why.
 */
export interface NotificationCheckResult {
  allowed: boolean;
  reason?: string;
}

/**
 * Check whether a notification should be sent based on user preferences.
 *
 * Rules:
 * 1. Non-email channels are always allowed (only email preferences exist).
 * 2. Global emailEnabled must be true.
 * 3. Per-category subscription must not be explicitly false (missing = enabled).
 * 4. Email frequency must be 'immediate' for instant delivery.
 */
export function checkNotificationPreferences(
  prefs: UserNotificationPreferences,
  type: NotificationType,
  channel: string,
): NotificationCheckResult {
  if (channel !== 'email') {
    return { allowed: true };
  }

  if (!prefs.emailEnabled) {
    return { allowed: false, reason: 'email disabled' };
  }

  const categoryEnabled = prefs.categorySubscriptions[type];
  if (categoryEnabled === false) {
    return { allowed: false, reason: `category '${type}' unsubscribed` };
  }

  if (prefs.emailFrequency !== 'immediate') {
    return { allowed: false, reason: `frequency is ${prefs.emailFrequency}` };
  }

  return { allowed: true };
}

