/**
 * Notification validators — pure validation functions for notification preferences.
 *
 * Extracted from PreferencesService.shouldSendNotification(). These functions
 * check user preferences without any side effects or data store access.
 *
 * Supports multi-channel validation: email uses `emailEnabled`,
 * other channels use `channelEnabled[channel]`.
 */

import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';

/**
 * Result of a notification preference check.
 * When `allowed` is false, `reason` explains why.
 */
export interface NotificationCheckResult {
  allowed: boolean;
  reason?: string;
}

/**
 * Check whether a channel is enabled in user preferences.
 *
 * - For email: checks `emailEnabled` (backward-compatible).
 * - For other channels: checks `channelEnabled[channel]`. Missing keys default to enabled.
 */
function isChannelEnabled(prefs: UserNotificationPreferences, channel: NotificationChannel): boolean {
  if (channel === 'email') {
    return prefs.emailEnabled;
  }
  const enabled = prefs.channelEnabled?.[channel];
  return enabled !== false; // missing = enabled
}

/**
 * Check whether a notification should be sent based on user preferences.
 *
 * Rules (applied per-channel):
 * 1. Channel must be enabled (emailEnabled for email, channelEnabled for others).
 * 2. Per-category subscription must not be explicitly false (missing = enabled).
 * 3. For email only: frequency must be 'immediate' for instant delivery.
 */
export function checkNotificationPreferences(
  prefs: UserNotificationPreferences,
  type: NotificationType,
  channel: string,
): NotificationCheckResult {
  const ch = channel as NotificationChannel;

  if (!isChannelEnabled(prefs, ch)) {
    return { allowed: false, reason: `${channel} disabled` };
  }

  const categoryEnabled = prefs.categorySubscriptions[type];
  if (categoryEnabled === false) {
    return { allowed: false, reason: `category '${type}' unsubscribed` };
  }

  if (channel === 'email' && prefs.emailFrequency !== 'immediate') {
    return { allowed: false, reason: `frequency is ${prefs.emailFrequency}` };
  }

  return { allowed: true };
}

